/**
 * Generate the shared TypeScript output contract from `docs/output-schema.json`.
 *
 * Writes the same `.d.ts` to two locations atomically:
 *   - editors/vscode/src/generated/output-contract.d.ts (consumed by the extension)
 *   - npm/fallow/types/output-contract.d.ts (published via `fallow/types` subpath)
 *
 * Both are committed to git. `--check` mode regenerates and diffs against both
 * files; CI fails if either drifts.
 *
 * Run: `pnpm --filter fallow-vscode codegen:types`
 *      `pnpm --filter fallow-vscode check:codegen`
 */
import { compile } from "json-schema-to-typescript";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const SCRIPT_DIR = dirname(fileURLToPath(import.meta.url));
const EXTENSION_ROOT = resolve(SCRIPT_DIR, "..");
const REPO_ROOT = resolve(EXTENSION_ROOT, "..", "..");
const SCHEMA_PATH = resolve(REPO_ROOT, "docs", "output-schema.json");
const SCHEMA_VERSION_SOURCE = resolve(
  REPO_ROOT,
  "crates",
  "cli",
  "src",
  "report",
  "json.rs",
);
const OUT_PATHS = [
  resolve(EXTENSION_ROOT, "src", "generated", "output-contract.d.ts"),
  resolve(REPO_ROOT, "npm", "fallow", "types", "output-contract.d.ts"),
];

const BANNER = `/**
 * AUTOGENERATED FILE. DO NOT EDIT.
 *
 * Generated from \`docs/output-schema.json\` by
 * \`editors/vscode/scripts/codegen-types.mjs\`. The same file is written to
 * \`editors/vscode/src/generated/output-contract.d.ts\` (extension internal) and
 * \`npm/fallow/types/output-contract.d.ts\` (published as \`fallow/types\`).
 *
 * To change a shape:
 *   1. Edit the Rust struct in \`crates/types/src/results.rs\` (or the
 *      duplicates crate at \`crates/core/src/duplicates/types.rs\`). The Rust
 *      side is the runtime source of truth for the JSON output.
 *   2. Update \`docs/output-schema.json\` to match. The schema is
 *      hand-maintained against the Rust structs; the drift-guard test in
 *      \`crates/cli/src/report/json.rs\` enforces only a subset of the
 *      contract (the \`HealthFindingAction\` enum). Field-level drift between
 *      Rust and the schema is currently caught by code review.
 *   3. Run \`pnpm --filter fallow-vscode codegen:types\` from anywhere.
 *   4. Commit both regenerated files alongside the schema edit.
 *
 * CI runs \`pnpm --filter fallow-vscode check:codegen\` which fails when
 * either committed file disagrees with what regen would produce.
 */
/* eslint-disable */
`;

const OPTIONS = {
  // Default for objects whose schema does not declare additionalProperties.
  // The schema is intentionally permissive at validation time (forward-compat
  // for JSON validators on older fallow versions), but for the TypeScript
  // contract we want closed shapes: missing-field reads should be a compile
  // error, not silent `unknown`.
  additionalProperties: false,
  bannerComment: BANNER,
  // Skip prettier formatting. jstt's raw output is stable across invocations,
  // which keeps the drift-check diff trivial. The committed file is read-only
  // for humans anyway.
  format: false,
  // Use `unknown` rather than `any` for the rare cases the schema admits it.
  unknownAny: true,
  // Include all named definitions, including helpers like SchemaVersion that
  // are referenced via $ref but not directly under the root oneOf.
  unreachableDefinitions: true,
  // Use the file path itself for ref resolution.
  cwd: REPO_ROOT,
};

/**
 * Strip `title` (and the root `$id`) from the schema before generation.
 * jstt prefers `title` over the definition key (or the explicit name argument
 * passed to `compile`) when naming generated types: documentary titles like
 * "fallow dead-code --format json" otherwise become mangled names like
 * `FallowDeadCodeFormatJson` (plus a duplicate `CheckOutput`), and the root
 * title "Fallow JSON Output Schemas" otherwise becomes `FallowJSONOutputSchemas`
 * regardless of the second argument to `compile`.
 *
 * `$id` has the same problem: when the root carries
 * `https://raw.githubusercontent.com/.../output-schema.json`, jstt mangles it
 * into `HttpsRawGithubusercontentComFallowRsFallowMainDocsOutputSchemaJson`.
 * The published schema needs `$id` for consumer SHA-pinning, but the TS
 * generation does not, so strip it here. `$comment` is documentary and ignored
 * by jstt; left in place.
 *
 * We keep `description` (used as JSDoc) and only drop `title` plus the root
 * `$id` (TS naming).
 */
function stripTitles(schema) {
  if ("title" in schema) {
    delete schema.title;
  }
  if ("$id" in schema) {
    delete schema.$id;
  }
  if (schema.definitions) {
    for (const def of Object.values(schema.definitions)) {
      if (def && typeof def === "object" && "title" in def) {
        delete def.title;
      }
    }
  }
  return schema;
}

/**
 * Walk the schema and remove sibling keys next to `$ref`. JSON Schema Draft 07
 * specifies that `$ref` siblings are ignored at validation time, but jstt
 * treats `{ "$ref": "...", "description": "..." }` as an inline schema and
 * generates a duplicate type rather than emitting a plain alias. Stripping
 * the `description` (and any other sibling) at codegen time keeps generated
 * names canonical without losing the documentation in the source schema.
 */
function flattenRefSiblings(node) {
  if (!node || typeof node !== "object") return node;
  if (Array.isArray(node)) {
    for (const item of node) flattenRefSiblings(item);
    return node;
  }
  if (typeof node.$ref === "string") {
    for (const key of Object.keys(node)) {
      if (key !== "$ref") delete node[key];
    }
    return node;
  }
  for (const value of Object.values(node)) flattenRefSiblings(value);
  return node;
}

/**
 * Read `const SCHEMA_VERSION: u32 = N;` from the canonical Rust source so the
 * generated TS pins `SchemaVersion` to the literal N (not bare `number`).
 *
 * Pinning lets downstream consumers gate on the schema version with a literal
 * type comparison: a major bump that changes the constant in Rust produces a
 * compile error at every call site that branches on the old literal, instead
 * of silently drifting.
 */
async function readRustSchemaVersion() {
  const source = await readFile(SCHEMA_VERSION_SOURCE, "utf8");
  const match = source.match(/const\s+SCHEMA_VERSION:\s*u32\s*=\s*(\d+)\s*;/);
  if (!match) {
    throw new Error(
      `Could not find \`const SCHEMA_VERSION: u32 = N;\` in ${SCHEMA_VERSION_SOURCE}`,
    );
  }
  return Number(match[1]);
}

/**
 * Post-process jstt's output to replace the bare `number` alias for
 * `SchemaVersion` with the literal pulled from Rust.
 *
 * Throws if the bare alias is missing: that would mean either jstt changed its
 * emission shape or the schema's SchemaVersion definition changed; either way
 * the pin is no longer reliable and the build should fail loudly.
 */
function pinSchemaVersion(contents, version) {
  const target = "export type SchemaVersion = number";
  if (!contents.includes(target)) {
    throw new Error(
      `pinSchemaVersion: expected to find \`${target}\` in generated output. ` +
        "Did jstt's emission change, or is `SchemaVersion` no longer a top-level " +
        "definition in docs/output-schema.json?",
    );
  }
  return contents.replace(target, `export type SchemaVersion = ${version}`);
}

/**
 * Strip trailing whitespace from each line. jstt's JSDoc renderer emits
 * paragraph breaks as `   * ` (asterisk + space + EOL), which trips
 * `git diff --check`'s whitespace gate and CI's repo-hygiene lint. The
 * downstream type semantics are unchanged.
 */
function stripTrailingWhitespace(contents) {
  return contents.replace(/[ \t]+$/gm, "");
}

/**
 * Schema definitions that json-schema-to-typescript dedupes because their
 * property set is fully subsumed by a parent type via `#[serde(flatten)]`.
 * Even with `unreachableDefinitions: true`, jstt suppresses the interface
 * when every property is already inlined on the flattening parent.
 *
 * For each entry, the codegen appends
 * `export type <name> = Omit<<parent>, "<wrapperOnly[0]>" | ...>;`
 * after generation. The schema still ships both definitions for JSON-schema
 * consumers (OpenAPI validators, doc-driven tooling); this alias exposes
 * the same shape to TypeScript consumers without forcing them to reach
 * through the wrapper.
 *
 * Adding new entries:
 *   1. Confirm jstt actually dedupes the new inner by inspecting the
 *      generated `.d.ts` for `export interface <inner-name>\b`. If
 *      present, the entry is unnecessary (and would conflict on the
 *      duplicate identifier).
 *   2. Append a `{ name, parent, wrapperOnlyFields, description }` row
 *      below.
 *   3. Regenerate via `pnpm --filter fallow-vscode codegen:types`.
 */
const FLATTEN_DEDUPED_ALIASES = [
  {
    name: "ComplexityViolation",
    parent: "HealthFinding",
    wrapperOnlyFields: ["actions", "introduced"],
    description:
      "Inner complexity-violation payload, flattened into `HealthFinding`\n" +
      " * on the wire via `#[serde(flatten)]`. Exposed here because\n" +
      " * json-schema-to-typescript dedupes definitions whose property set is\n" +
      " * fully subsumed by a flattening parent; the schema definition exists\n" +
      " * in `docs/output-schema.json` but the TS interface is suppressed.\n" +
      " * Consumers that need to type just the inner payload should use this\n" +
      " * alias; consumers that need the full envelope (with `actions` and\n" +
      " * optional `introduced`) should use `HealthFinding` directly.",
  },
  {
    name: "HotspotEntry",
    parent: "HotspotFinding",
    wrapperOnlyFields: ["actions"],
    description:
      "Inner hotspot payload, flattened into `HotspotFinding` on the wire\n" +
      " * via `#[serde(flatten)]`. Exposed here for the same reason as\n" +
      " * `ComplexityViolation`: jstt dedupes the inner because its property\n" +
      " * set is fully subsumed by the wrapper. Consumers that want only the\n" +
      " * inner shape should use this alias; consumers that need the full\n" +
      " * envelope with `actions` should use `HotspotFinding` directly.\n" +
      " * Unlike `HealthFinding`, the wrapper does not carry `introduced`\n" +
      " * because hotspot ranking does not run through audit attribution.",
  },
  {
    name: "RefactoringTarget",
    parent: "RefactoringTargetFinding",
    wrapperOnlyFields: ["actions"],
    description:
      "Inner refactoring-target payload, flattened into\n" +
      " * `RefactoringTargetFinding` on the wire via `#[serde(flatten)]`.\n" +
      " * Exposed here for the same reason as `ComplexityViolation`: jstt\n" +
      " * dedupes the inner because its property set is fully subsumed by\n" +
      " * the wrapper. Consumers that want only the inner shape should use\n" +
      " * this alias; consumers that need the full envelope with `actions`\n" +
      " * should use `RefactoringTargetFinding` directly. Unlike\n" +
      " * `HealthFinding`, the wrapper does not carry `introduced` because\n" +
      " * refactoring targets do not run through audit attribution.",
  },
  {
    name: "CloneGroup",
    parent: "CloneGroupFinding",
    wrapperOnlyFields: [],
    description:
      "Backwards-compat alias for the pre-#409 bare clone-group name.\n" +
      " * jstt dedupes the bare interface because every field is fully\n" +
      " * subsumed by `CloneGroupFinding` (the wrapper flattens the bare\n" +
      " * `CloneGroup` via `#[serde(flatten)]`). Aliased to the full\n" +
      " * wrapper (not `Omit<>`-stripped) because the pre-migration wire\n" +
      " * always carried `actions[]` on every clone group via the legacy\n" +
      " * `inject_dupes_actions` post-pass, so the bare alias matching the\n" +
      " * wrapper shape is the byte-faithful continuation. Consumers that\n" +
      " * imported `CloneGroup` from `fallow/types` pre-migration continue\n" +
      " * to work via this alias; new code should prefer `CloneGroupFinding`.",
  },
  {
    name: "CloneFamily",
    parent: "CloneFamilyFinding",
    wrapperOnlyFields: [],
    description:
      "Backwards-compat alias for the pre-#409 bare clone-family name.\n" +
      " * jstt dedupes the bare interface because every field is subsumed\n" +
      " * by `CloneFamilyFinding`. The wrapper's `groups[]` items are\n" +
      " * `CloneGroupFinding` rather than bare `CloneGroup`, which matches\n" +
      " * the pre-migration wire shape (the legacy `inject_dupes_actions`\n" +
      " * post-pass injected `actions[]` on every nested group too).\n" +
      " * Consumers that imported `CloneFamily` from `fallow/types`\n" +
      " * pre-migration continue to work via this alias; new code should\n" +
      " * prefer `CloneFamilyFinding`.",
  },
  {
    name: "AttributedCloneGroup",
    parent: "AttributedCloneGroupFinding",
    wrapperOnlyFields: [],
    description:
      "Backwards-compat alias for the pre-#409 bare attributed-clone-group\n" +
      " * name (`fallow dupes --group-by` per-bucket attribution).\n" +
      " * Consumers that imported `AttributedCloneGroup` from `fallow/types`\n" +
      " * pre-migration continue to work via this alias; new code should\n" +
      " * prefer `AttributedCloneGroupFinding`.",
  },
  {
    name: "DuplicationReport",
    parent: "DupesReportPayload",
    wrapperOnlyFields: [],
    description:
      "Backwards-compat alias for the pre-#409 `DuplicationReport` name.\n" +
      " * The wire shape is byte-identical between the two: the typed\n" +
      " * `DupesReportPayload` mirrors `DuplicationReport` field-for-field\n" +
      " * with `clone_groups[]` / `clone_families[]` carrying typed\n" +
      " * `CloneGroupFinding` / `CloneFamilyFinding` wrappers instead of\n" +
      " * bare findings (the pre-migration wire ALSO carried `actions[]`\n" +
      " * on each item via the legacy `inject_dupes_actions` post-pass).\n" +
      " * Consumers that imported `DuplicationReport` from `fallow/types`\n" +
      " * pre-migration continue to work via this alias; new code should\n" +
      " * prefer `DupesReportPayload`.",
  },
];

/**
 * Bare-name backwards-compat aliases for the dead-code findings wrapped by
 * the #384 schema-derive ladder. Each maps the pre-wrapper bare name to its
 * `*Finding` envelope. jstt drops the orphan inner definitions because every
 * field is subsumed by the flattening wrapper, so external `fallow/types`
 * consumers importing the bare names would break at upgrade time without
 * these aliases. The published v2.x stable surface guarantees the bare
 * names; the kind-tagged `FallowOutput` major bump (#413) will remove them
 * after one minor cycle of `@deprecated` JSDoc.
 *
 * Generated under the same "Backwards-compat aliases" section as the
 * `FLATTEN_DEDUPED_ALIASES` dupes / health-secondary entries.
 */
const BARE_DEAD_CODE_ALIASES = [
  { name: "BoundaryViolation", parent: "BoundaryViolationFinding" },
  { name: "CircularDependency", parent: "CircularDependencyFinding" },
  { name: "DuplicateExport", parent: "DuplicateExportFinding" },
  { name: "EmptyCatalogGroup", parent: "EmptyCatalogGroupFinding" },
  {
    name: "MisconfiguredDependencyOverride",
    parent: "MisconfiguredDependencyOverrideFinding",
  },
  { name: "PrivateTypeLeak", parent: "PrivateTypeLeakFinding" },
  { name: "ReExportCycle", parent: "ReExportCycleFinding" },
  { name: "TestOnlyDependency", parent: "TestOnlyDependencyFinding" },
  { name: "TypeOnlyDependency", parent: "TypeOnlyDependencyFinding" },
  { name: "UnlistedDependency", parent: "UnlistedDependencyFinding" },
  {
    name: "UnresolvedCatalogReference",
    parent: "UnresolvedCatalogReferenceFinding",
  },
  { name: "UnresolvedImport", parent: "UnresolvedImportFinding" },
  { name: "UnusedCatalogEntry", parent: "UnusedCatalogEntryFinding" },
  {
    name: "UnusedDependencyOverride",
    parent: "UnusedDependencyOverrideFinding",
  },
  { name: "UnusedExport", parent: "UnusedExportFinding" },
  { name: "UnusedFile", parent: "UnusedFileFinding" },
];

/**
 * Bare-name union aliases for the dead-code findings whose pre-wrapper
 * shape was a union of multiple `*Finding` types (e.g. pre-#384
 * `UnusedDependency` covered the production / dev / optional dep variants).
 * The wire shape is unchanged; the bare names exist for the same
 * `json-schema-to-typescript` orphan reason as `BARE_DEAD_CODE_ALIASES`.
 */
const BARE_DEAD_CODE_UNION_ALIASES = [
  {
    name: "UnusedDependency",
    parents: [
      "UnusedDependencyFinding",
      "UnusedDevDependencyFinding",
      "UnusedOptionalDependencyFinding",
    ],
  },
  {
    name: "UnusedMember",
    parents: ["UnusedClassMemberFinding", "UnusedEnumMemberFinding"],
  },
];

/**
 * Header emitted above the appended aliases so the published
 * `npm/fallow/types/output-contract.d.ts` (and the extension-internal
 * mirror) carry the alias policy inline. Public-consumer reference lives
 * in `docs/backwards-compatibility.md`; this block is the in-file
 * shorthand for npm consumers grepping their `node_modules`.
 */
const BACKWARDS_COMPAT_ALIASES_HEADER = `
//
// =============================================================================
// Backwards-compat aliases
// =============================================================================
//
// The aliases below map pre-#384 / #408 / #409 bare names to their typed
// envelope wrappers. The wire shape is byte-identical: each wrapper flattens
// the bare finding's fields via \`#[serde(flatten)]\` and adds \`actions[]\`
// (and, where the wrapper participates in \`fallow audit\` attribution, the
// optional \`introduced\` flag). Per-alias rationale lives in each alias's
// JSDoc below.
//
// Why these aliases exist: \`json-schema-to-typescript\` drops the orphan
// inner definitions for \`#[serde(flatten)]\` wrappers (even with
// \`unreachableDefinitions: true\`), so the bare names disappear from this
// generated \`.d.ts\` without an explicit alias. External consumers that
// import the bare names from \`fallow/types\` would break at upgrade time
// otherwise.
//
// Stability commitment: these aliases ship as part of fallow's v2.x stable
// surface. They are scheduled for removal alongside the kind-tagged
// \`FallowOutput\` major bump (see https://github.com/fallow-rs/fallow/issues/413),
// with a one-minor-cycle deprecation window (\`@deprecated\` JSDoc +
// CHANGELOG headline) preceding the removal. New code should prefer the
// \`*Finding\` wrapper names. Full public-consumer policy:
// https://github.com/fallow-rs/fallow/blob/main/docs/backwards-compatibility.md
//
`;

/**
 * Build the JSDoc description for a uniform `BARE_DEAD_CODE_ALIASES` entry
 * (`X = XFinding`). Kept terse because each alias has the same rationale:
 * #384 wrapped the bare finding and jstt drops the orphan.
 */
function bareDeadCodeAliasDescription(name, parent) {
  return (
    `Backwards-compat alias for the pre-#384 bare \`${name}\` name.\n` +
    ` * The wire shape is byte-identical: \`${parent}\` flattens the bare\n` +
    ` * finding's fields via \`#[serde(flatten)]\` and adds \`actions[]\` plus\n` +
    ` * the optional audit-mode \`introduced\` flag. Consumers that imported\n` +
    ` * \`${name}\` from \`fallow/types\` pre-migration continue to work via\n` +
    ` * this alias; new code should prefer \`${parent}\`.`
  );
}

/**
 * Build the JSDoc description for a `BARE_DEAD_CODE_UNION_ALIASES` entry
 * (`X = A | B | ...`). Same rationale as the single-parent template.
 */
function bareDeadCodeUnionAliasDescription(name, parents) {
  return (
    `Backwards-compat alias for the pre-#384 bare \`${name}\` union name.\n` +
    ` * Maps to the union of typed wrappers (${parents.map((p) => `\`${p}\``).join(", ")})\n` +
    ` * that replaced the pre-migration bare union. The wire shape per variant\n` +
    ` * is byte-identical (each wrapper flattens its bare payload and adds\n` +
    ` * \`actions[]\` plus optional \`introduced\`). Consumers that imported\n` +
    ` * \`${name}\` from \`fallow/types\` pre-migration continue to work via\n` +
    ` * this alias; new code should narrow on the specific wrapper variant.`
  );
}

/**
 * Append aliases for serde-flattened inner types that jstt dedupes (see
 * `FLATTEN_DEDUPED_ALIASES` for the full rationale and extension recipe).
 *
 * When `wrapperOnlyFields` is empty, emits `export type Name = Parent` (a
 * full alias) instead of `export type Name = Omit<Parent, ...>` (an Omit
 * alias with no fields to omit). Used for bare types whose property set is
 * BYTE-IDENTICAL to the wrapper on the wire (e.g., the pre-wrapper
 * `DuplicationReport` whose `clone_groups[]` items always carried injected
 * `actions[]` even before the typed wrapper migration).
 */
function appendDedupedFlattenAliases(contents) {
  let out = contents;
  let backwardsCompatHeaderEmitted = false;
  for (const alias of FLATTEN_DEDUPED_ALIASES) {
    const isBackwardsCompat = alias.description.startsWith(
      "Backwards-compat alias",
    );
    if (isBackwardsCompat && !backwardsCompatHeaderEmitted) {
      out += BACKWARDS_COMPAT_ALIASES_HEADER;
      backwardsCompatHeaderEmitted = true;
    }
    const rhs = alias.wrapperOnlyFields.length === 0
      ? alias.parent
      : `Omit<${alias.parent}, ${alias.wrapperOnlyFields
          .map((field) => `"${field}"`)
          .join(" | ")}>`;
    out += `\n/**\n * ${alias.description}\n */\nexport type ${alias.name} = ${rhs};\n`;
  }
  // Emit the BARE_DEAD_CODE_* tables under the same "Backwards-compat
  // aliases" section header. If FLATTEN_DEDUPED_ALIASES had no
  // backwards-compat entries, drop the header here so the section still
  // gets one explanatory block before the first dead-code alias.
  if (!backwardsCompatHeaderEmitted) {
    out += BACKWARDS_COMPAT_ALIASES_HEADER;
    backwardsCompatHeaderEmitted = true;
  }
  for (const alias of BARE_DEAD_CODE_ALIASES) {
    const description = bareDeadCodeAliasDescription(alias.name, alias.parent);
    out += `\n/**\n * ${description}\n */\nexport type ${alias.name} = ${alias.parent};\n`;
  }
  for (const alias of BARE_DEAD_CODE_UNION_ALIASES) {
    const description = bareDeadCodeUnionAliasDescription(
      alias.name,
      alias.parents,
    );
    out += `\n/**\n * ${description}\n */\nexport type ${alias.name} = ${alias.parents.join(" | ")};\n`;
  }
  return out;
}

/**
 * Verify each `FLATTEN_DEDUPED_ALIASES` entry actually landed in the
 * generated `.d.ts`, AND that its `parent` interface exists (otherwise the
 * `Omit<Parent, ...>` alias would not resolve at consumer type-check time).
 *
 * Throws if either invariant is violated. Catches three drift scenarios:
 *   1. `appendDedupedFlattenAliases` regressed (e.g. typo in the emit
 *      template) and the alias is missing from the output.
 *   2. The parent type was renamed in the schema (e.g. `HealthFinding` to
 *      `HealthFindingEnvelope`) but the alias entry still references the
 *      old name. The alias would emit `Omit<<old-name>, ...>` and break.
 *   3. The parent type got dedupe-suppressed itself (e.g. someone wrapped
 *      `HealthFinding` in another `#[serde(flatten)]` wrapper). The
 *      alias would silently resolve to an unknown type.
 *
 * Future-proofing note: if jstt starts emitting the inner natively (e.g. a
 * version bump that disables the subsume-dedupe heuristic), the alias and
 * the natively-emitted interface would conflict on a duplicate identifier
 * and `pnpm run lint` (tsc --noEmit) would fail; this assertion is
 * deliberately narrower so the failure surfaces at codegen time first.
 */
function assertAliasesEmitted(contents) {
  const assertAlias = (name, parents, table) => {
    const aliasRe = new RegExp(`^export type ${name}\\b`, "m");
    if (!aliasRe.test(contents)) {
      throw new Error(
        `assertAliasesEmitted: expected \`export type ${name}\` in generated output. ` +
          `If jstt now emits this type natively or it was renamed, update ${table}.`,
      );
    }
    for (const parent of parents) {
      const parentRe = new RegExp(`^export interface ${parent}\\b`, "m");
      if (!parentRe.test(contents)) {
        throw new Error(
          `assertAliasesEmitted: expected \`export interface ${parent}\` (parent of ${name}) in generated output. ` +
            `The alias for \`${name}\` would fail to resolve without it. ` +
            `Did ${parent} get renamed or dedupe-suppressed?`,
        );
      }
    }
  };
  for (const alias of FLATTEN_DEDUPED_ALIASES) {
    assertAlias(alias.name, [alias.parent], "FLATTEN_DEDUPED_ALIASES");
  }
  for (const alias of BARE_DEAD_CODE_ALIASES) {
    assertAlias(alias.name, [alias.parent], "BARE_DEAD_CODE_ALIASES");
  }
  for (const alias of BARE_DEAD_CODE_UNION_ALIASES) {
    assertAlias(alias.name, alias.parents, "BARE_DEAD_CODE_UNION_ALIASES");
  }
}

async function generate() {
  const raw = await readFile(SCHEMA_PATH, "utf8");
  const parsed = JSON.parse(raw);
  stripTitles(parsed);
  flattenRefSiblings(parsed);
  // With the root title stripped, jstt uses the second arg as the name of the
  // top-level union type.
  const raw_ts = await compile(parsed, "FallowJsonOutput", OPTIONS);
  const version = await readRustSchemaVersion();
  const final = appendDedupedFlattenAliases(
    stripTrailingWhitespace(pinSchemaVersion(raw_ts, version)),
  );
  assertAliasesEmitted(final);
  return final;
}

async function writeAll(contents) {
  for (const path of OUT_PATHS) {
    await mkdir(dirname(path), { recursive: true });
    await writeFile(path, contents, "utf8");
  }
}

async function check() {
  const generated = await generate();
  const stale = [];
  for (const path of OUT_PATHS) {
    const committed = await readFile(path, "utf8").catch(() => "");
    if (committed !== generated) {
      stale.push(path);
    }
  }
  if (stale.length === 0) {
    return 0;
  }
  process.stderr.write(
    "\x1b[31mcheck:codegen FAILED\x1b[0m: the following generated files " +
      "are out of date with `docs/output-schema.json`:\n",
  );
  for (const path of stale) {
    process.stderr.write(`  - ${path}\n`);
  }
  process.stderr.write(
    "Run `pnpm --filter fallow-vscode codegen:types` and commit the result.\n",
  );
  return 1;
}

const mode = process.argv[2];
if (mode === "--check") {
  const code = await check();
  process.exit(code);
} else {
  const contents = await generate();
  await writeAll(contents);
  for (const path of OUT_PATHS) {
    process.stdout.write(`Wrote ${path}\n`);
  }
}
